-- Ken's Hardened V2 Fix

local b64_0xll1lll = {}
local char_0xIII11I='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xll1Il1=1,#char_0xIII11I do b64_0xll1lll[char_0xIII11I:sub(i_0xll1Il1,i_0xll1Il1)] = i_0xll1Il1 - 1 end

function b64_0xll1lll.dec_0xl1IlI1(d_0xlIlII1)
    d_0xlIlII1 = string.gsub(d_0xlIlII1, '[^'..char_0xIII11I..'=]', '')
    local r_0xIl11Il = {}
    for i_0xll1Il1=1, #d_0xlIlII1, 4 do
        local c_0xll1III = b64_0xll1lll[d_0xlIlII1:sub(i_0xll1Il1,i_0xll1Il1)] or 0
        local c_0x1II1Il = b64_0xll1lll[d_0xlIlII1:sub(i_0xll1Il1+1,i_0xll1Il1+1)] or 0
        local c_0x1lIll1, c_0xIlIllI = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlIlII1:sub(i_0xll1Il1+2,i_0xll1Il1+2)
        if ch3 == "=" then has3 = false else c_0x1lIll1 = b64_0xll1lll[ch3] or 0 end
        local ch4 = d_0xlIlII1:sub(i_0xll1Il1+3,i_0xll1Il1+3)
        if ch4 == "=" then has4 = false else c_0xIlIllI = b64_0xll1lll[ch4] or 0 end
        local b_0xlIllI1 = c_0xll1III * (2^18) + c_0x1II1Il * (2^12) + c_0x1lIll1 * (2^6) + c_0xIlIllI
        local b_0xIlIIII = math.floor(b_0xlIllI1 / (2^16)) % (2^8)
        local b_0x1l1IIl = math.floor(b_0xlIllI1 / (2^8)) % (2^8)
        local b_0xI1IIIl = b_0xlIllI1 % (2^8)
        table.insert(r_0xIl11Il, string.char(b_0xIlIIII))
        if has3 then table.insert(r_0xIl11Il, string.char(b_0x1l1IIl)) end
        if has4 then table.insert(r_0xIl11Il, string.char(b_0xI1IIIl)) end
    end
    return table.concat(r_0xIl11Il)
end


local function bxor_0xlI1ll1(a_0xlI11I1,b_0xIlllIl)
    if bit32 then return bit32.bxor(a_0xlI11I1,b_0xIlllIl) end
    local r_0xIl11lI = 0
    for i_0xIIlllI = 0, 7 do
        local x_0xlIll11 = a_0xlI11I1 % 2
        local y_0xIlII1I = b_0xIlllIl % 2
        if x_0xlIll11 ~= y_0xIlII1I then r_0xIl11lI = r_0xIl11lI + (2^i_0xIIlllI) end
        a_0xlI11I1 = math.floor(a_0xlI11I1 / 2)
        b_0xIlllIl = math.floor(b_0xIlllIl / 2)
    end
    return r_0xIl11lI
end


local function bxor_str_0xIl1III(s_0xlIl1lI, k_0xII1III)
    local r_0x1Il11I = {}
    for i_0x1llIIl=1, #s_0xlIl1lI do
        local b_0xI1I1lI = string.byte(s_0xlIl1lI, i_0x1llIIl)
        local kb_0xl1llll = string.byte(k_0xII1III, (i_0x1llIIl-1) % #k_0xII1III + 1)
        r_0x1Il11I[i_0x1llIIl] = string.char(bxor_0xlI1ll1(b_0xI1I1lI, kb_0xl1llll))
    end
    return table.concat(r_0x1Il11I)
end


local function getkeys_0xlllII1()
    local seed = b64_0xll1lll.dec_0xl1IlI1("M3FrdGt3eFU=")
    local k1_enc = b64_0xll1lll.dec_0xl1IlI1("eT9aRwYVCy0=")
    local k2_enc = b64_0xll1lll.dec_0xl1IlI1("ajAPGSodGgI=")
    return bxor_str_0xIl1III(k1_enc, seed), bxor_str_0xIl1III(k2_enc, seed)
end


local function cff_0xIllIlI(a_0xIIllll)
    local st_0x1IlIl1 = 0
    local res_0xlIIl1l = a_0xIIllll
    while true do
        if st_0x1IlIl1 == 0 then
            res_0xlIIl1l = res_0xlIIl1l + 1
            st_0x1IlIl1 = 1
        elseif st_0x1IlIl1 == 1 then
            res_0xlIIl1l = res_0xlIIl1l * 2
            st_0x1IlIl1 = 2
        elseif st_0x1IlIl1 == 2 then
            res_0xlIIl1l = res_0xlIIl1l - 3
            st_0x1IlIl1 = 3
        else
            break
        end
    end
    return res_0xlIIl1l
end


local function chain_0x11IIl1(x) return x*2 end
local function chain_0x1IIlIl(x) return chain_0x11IIl1(x)+1 end


local d_0xl1I1l1 = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIlIIl = 1
local stk_0xI11lI1 = {}
stk_0xI11lI1._jmp = nil


local disp_0xlllIlI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xlllII1()

local state_0xll11lI = 0
while true do
    if state_0xll11lI == 0 then  -- FETCH
        if pc_0xlIlIIl > #d_0xl1I1l1 then break end
        local inst = d_0xl1I1l1[pc_0xlIlIIl]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xll1lll.dec_0xl1IlI1(val)
            d = bxor_str_0xIl1III(d, k2)
            val = bxor_str_0xIl1III(d, k1)
        end
        stk_0xI11lI1._jmp = nil
        pc_0xlIlIIl = pc_0xlIlIIl + 1
        cur_op_0xI11IIl = opcode
        cur_val_0xl1lllI = val
        state_0xll11lI = 1

    elseif state_0xll11lI == 1 then  -- EXECUTE
        local handler = disp_0xlllIlI[cur_op_0xI11IIl]
        if handler then
            handler(stk_0xI11lI1, cur_val_0xl1lllI)
        end
        if stk_0xI11lI1._jmp then
            pc_0xlIlIIl = pc_0xlIlIIl + stk_0xI11lI1._jmp
        end
        state_0xll11lI = 0
